-- Batch 86 (431-435)
-- 北原 (Kitahara), 篠田 (Shinoda), 富永 (Tominaga), 汤浅 (Yuasa), 鹤田 (Tsuruta)

UPDATE names SET 
  description_zh = '“北”指北境，“原”指平原。意指位于北方的辽阔沃野，象征着清冽的空气、独立与坚韧。北原姓氏展现出一种清正、孤高且极具艺术气息的意境（因诗人北原白秋而富有极高的人文色彩），象征着家族具有澄澈的心境、性格如冰雪般纯粹且在文学或艺术领域具有卓越的才华，给人以脱俗、睿智且底蕴深厚的深刻印象。',
  description_en = 'Kitahara means "northern plain," referring to vast fertile fields located in the north. It symbolizes crisp air, independence, and resilience. The name showcases a sense of integrity, lofty solitude, and artistic flair (carrying high cultural weight through poet Hakushu Kitahara). It symbolizes a family with a clear, untainted mind and a personality as pure as snow, possessing exceptional talent in literature or the arts, projecting an image of transcendence, wisdom, and deep historical resonance.',
  meaning_zh = '北境清原',
  meaning_en = 'Northern Plain / Snowy Field',
  kamon_prompt = 'A circular Japanese kamon featuring stylized geometric patterns of vast plains combined with the "Yuki-mon" (snowflake) or cold-climate floral motifs within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"北原 白秋","name_jp":"北原 白秋","context":"文学者 | 歌人、詩人、童謡作家 | 1885年 1月 25日"},{"name":"北原 里英","name_jp":"北原 里英","context":"芸能人 | 元アイドル（AKB48、NGT48） | 1991年 6月 24日"},{"name":"北原 謙","name_jp":"北原 謙","context":"政治家 | 自由民権運動家 | 1851年"}]'
WHERE romaji = 'kitahara' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“篠”指纤细而坚韧的小竹，“田”指农田。意指茂密细竹点缀的优质耕地，象征着优雅与坚韧并蓄的生存哲学。篠田姓氏展现出一种洗练、明快且极具现代感官的意境，象征着家族具有敏锐的审美观、性格坚定且在群体中因个性的独立而备受关注，给人以斯文、儒雅且充满格调的深刻印象。',
  description_en = 'Shinoda means "bamboo-grass field," referring to high-quality farmland adorned with slender, resilient bamboo grass. It symbolizes a survival philosophy that balances elegance with tenacity. The name showcases a sense of refinement, brightness, and modern style. It symbolizes a lineage with keen aesthetic sensibilities and a firm personality that stands out for its independence, projecting an image of scholarly grace, nobility, and sophisticated charm.',
  meaning_zh = '翠篠良田',
  meaning_en = 'Bamboo-Grass Field / Slender Grove Farm',
  kamon_prompt = 'A circular Japanese kamon featuring stylized bamboo leaves arranged in a grid-like or field-representative pattern within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"篠田 麻里子","name_jp":"篠田 麻里子","context":"芸能人 | 元アイドル（AKB48）、俳優 | 1986年 3月 11日"},{"name":"篠田 謙","name_jp":"篠田 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"篠田 正浩","name_jp":"篠田 正浩","context":"芸能人 | 映画監督 | 1931年 3月 9日"}]'
WHERE romaji = 'shinoda' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“富”指丰裕、昌盛，“永”指恒久。意指祝愿财富与福华能够代代相传、永不枯竭的吉祥愿景，象征着家族受运势长久眷顾。富永姓氏展现出一种华美、稳健且极其阳光的意境，象征着家族具有极其深厚的德行积淀、性格豪爽且具有源源不断的生命活力，给人以幸福、显赫且极其可靠的深刻印象。',
  description_en = 'Tominaga means "eternal wealth" or "permanent prosperity," referring to the wish that fame and riches will endure through generations without end. It symbolizes a family whose fortune is consistently favored by destiny. The name showcases a sense of splendor, stability, and optimism. It symbolizes a lineage with deep moral accumulation and a bold personality filled with continuous vitality, projecting an image of happiness, prestige, and absolute reliability.',
  meaning_zh = '富贵永传',
  meaning_en = 'Eternal Wealth / Perpetual Prosperity',
  kamon_prompt = 'A circular Japanese kamon featuring the "Tominaga-gasane" (overlapping diamonds/circles) or stylized "rich" character motifs within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"富永 愛","name_jp":"冨永 愛","context":"芸能人 | モデル、俳優 | 1982年 8月 1日"},{"name":"富永 謙","name_jp":"富永 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"富永 仲基","name_jp":"富永 仲基","context":"文化人 | 江戸時代の思想家 | 1715年"}]'
WHERE romaji = 'tominaga' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“汤”指温暖的泉水或沸腾的江河，“浅”指宽阔的浅滩。意指热气腾腾、具有治愈之力的宽阔水泽，象征着家族具有如同暖泉般包容且治愈他人的特质。汤浅姓氏展现出一种温暖、清澈且极具包容力的意境，象征着家族性格温和、为人处世富有智慧且在学术或教育等领域具有深厚的传统，给人以平和、睿智且极其亲切的强烈印象。',
  description_en = 'Yuasa means "hot-spring shallows," referring to a wide, steaming waterway with healing powers. It symbolizes a family with the qualities of a warm spring that embraces and heals others. The name showcases a sense of warmth, clarity, and inclusivity. It symbolizes a lineage with a mild personality and wise conduct, holding deep traditions in fields like academia or education, projecting an image of peace, wisdom, and exceptional friendliness.',
  meaning_zh = '暖泉浅滩',
  meaning_en = 'Hot-Spring Shallows / Healing Waters',
  kamon_prompt = 'A circular Japanese kamon featuring stylized steam or rhythmic water ripple motifs (Sui-mon) combined with shallow geometric markers within a circle, solid black on a white background.',
  famous_bearers = '[{"name":"湯浅 政明","name_jp":"湯浅 政明","context":"文化人 | アニメーション監督 | 1965年 3月 16日"},{"name":"湯浅 謙","name_jp":"湯浅 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"湯浅 卓","name_jp":"湯浅 卓","context":"文化人 | 弁護士、タレント | 1955年 11月 24日"}]'
WHERE (kanji = '湯浅' OR kanji = '汤浅') AND romaji = 'yuasa' AND name_part = 'family_name';

UPDATE names SET 
  description_zh = '“鹤”指高洁长寿的神鸟，“田”指农田。意指有瑞鹤栖息、受神灵守护的肥沃耕地，象征着极其长久的生命力、高洁的志趣与繁荣的基石。鹤田姓氏展现出一种雅致、肃穆且极具生命美感的意境，象征着家族品格高尚、性格稳重且在艺术或某一专业领域具有超凡脱俗的表现力，给人以高贵、知性且富有底蕴的深刻印象。',
  description_en = 'Tsuruta means "crane field," referring to fertile farmland where sacred cranes dwell, symbolizing divine protection. It signifies extraordinary longevity, noble interests, and the foundation of prosperity. The name showcases a sense of elegance, solemnity, and biological beauty. It symbolizes a lineage with high moral standards and a steady personality, possessing transcendent expressive power in arts or specialized fields, projecting an image of nobility, intellect, and rich heritage.',
  meaning_zh = '瑞鹤沃田',
  meaning_en = 'Crane Field / Sacred Farm',
  kamon_prompt = 'A circular Japanese kamon featuring the "Tsuru-no-maru" (crane in a circle) with a stylized field pattern background, solid black on a white background.',
  famous_bearers = '[{"name":"鶴田 謙","name_jp":"鶴田 謙","context":"政治家 | 自由民権運動家 | 1851年"},{"name":"鶴田 浩二","name_jp":"鶴田 浩二","context":"芸能人 | 俳優、歌手 | 1924年 12月 6日"},{"name":"ジャンボ鶴田","name_jp":"ジャンボ鶴田","context":"スポーツ選手 | プロレスラー | 1951年 3月 25日"}]'
WHERE romaji = 'tsuruta' AND name_part = 'family_name';
